var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"끝났습니다. 당분간 항해하는 데에는 지장 없을 거예요.","JPN":"終わりました。しばらく航海に差し支えはないはずです。","ENG":"It's done. You won't have any trouble sailing for the time being.","TWN":"好了。暫時不會影響航行。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"대단한데, 알바생 양반? 이 정도 솜씨는 프론트베이에서도 찾아보기 힘들 정도야.","JPN":"すごいな、バイトさん。これほどの腕前はフロントベイでも探すのは大変だ。","ENG":"Not too shabby, little girl. It's hard to come by someone with this level of skill in Front Bay.","TWN":"了不起啊，小妹妹？這種手藝在前灣都很難找到。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"싼값을 부를 때는 긴가민가했는데, 이 참에 터커 해적단에 정식으로 입단하는 건 어때?","JPN":"代金が安いから腕を疑っていたが、これを機にターカー海賊団に正式入団したらどうだ？","ENG":"I was skeptical when you asked for so little. But say, how about you officially join the Tucker Pirates?","TWN":"當時你開價那麼低，我還半信半疑的，要不趁這個機會正式加入塔克海盜團怎麼樣？"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"사양할게요. 해적이 되려고 이런 먼 지역까지 온 건 아니라서요.","JPN":"お断りします。海賊になるためにこんな遠いところまで来たわけじゃないんで。","ENG":"I'll have to decline. I didn't come all the way over here to become a pirate.","TWN":"我還是算了吧。我可不是為了當海盜才跑到這麼遠的地方來的。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"대금은 평소대로 편의점 아포칼립스로 부탁드릴게요.","JPN":"代金はいつもどおりコンビニアポカリプスにお願いします。","ENG":"Payment should go to Apocalypse Convenience Store as usual.","TWN":"費用請照常在便利商店 阿波卡利斯進行支付。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"걱정 마. 평소 정비에 쓰는 비용을 생각하면 남는 장사니까.","JPN":"心配するな。普段整備に使ってる費用を考えるとお得だからな。","ENG":"Of course. This is quite affordable for me, considering the amount I used to pay for maintenance.","TWN":"當然。相比正常的維修費用，我們可是撿了個大便宜。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"내가 말하기 뭣하지만 남는 게 있는 거야?","JPN":"俺が言うのもなんだが、ちゃんと利益は出ているのか？","ENG":"Just out of curiosity, do you even make any money from doing this?","TWN":"但我有些好奇，你們這樣也有賺嗎？"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"글쎄요. 워낙 적자인 지점이 많아서 이정도면 남는 장사 아닐까 싶네요.","JPN":"さあ？　赤字の支店が多いですから、これくらいなら儲かってるんじゃないかなと思いますけど。","ENG":"I don't know. There are a lot of branches that are running at a loss, so I guess so?","TWN":"嗯……因為虧損的分店太多了，所以這樣的話，應該算是有得賺？"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"저희 매출 걱정도 좋지만 터커 씨는 저랑 한 약속이나 지켜주세요.","JPN":"私たちの売り上げを心配するのもいいですが、ターカーさんは私との約束を守ってくださいね。","ENG":"I appreciate your concern about our revenue, but just remember to keep your promise to me, Tucker.","TWN":"擔心我們是好事，但是塔克先生，請先遵守和我的約定。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"그래. 네가 우리 해적단의 배를 정기적으로 수리해주는 대신……","JPN":"ああ。お前が我が海賊団の船を定期的に修理してくれる代わりに……","ENG":"Sure. In return for you regularly fixing our pirate ships...","TWN":"好吧，你定期修理我們海盜團的船隻，作為交換……"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"그쪽은 절 배에 태워준다. 보물을 발견하면 한 사람 몫만큼은 챙겨 주시고요.","JPN":"そちらは私を船に乗せる。お宝を見つけたら、私の取り分もちゃんとくださいよ。","ENG":"You let me ride your ship. And you give me a share of the treasure you find.","TWN":"你們帶我上船。如果發現寶物，至少給我一份。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"캬하하! 설마 편의점 알바생이랑 거래를 하는 날이 올 줄은 몰랐는데 말이야.","JPN":"ガハハ！　まさかコンビニのバイトと取引をする日が来るなんてな。","ENG":"Kya ha ha! Who would've thought I'd be making a deal with a part-time convenience store employee.","TWN":"哈哈哈！沒想到有一天會和便利商店的小妹妹做交易。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"나야 상관없지만… 알고 있겠지, 알바생 양반?","JPN":"俺はいいが……わかってるだろうな、バイトさん。","ENG":"It's fine with me, but... you know what you're getting into, right?","TWN":"我倒是無所謂……不過你知道的吧，小妹妹？"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"프론트베이 해역은 관리국 허가 없이는 돌아다닐 수 없어.","JPN":"フロントベイの海域は管理局の許可なしでは動き回れない。","ENG":"You can't travel around the Front Bay waters without permission from the Administration.","TWN":"沒有管理局的許可，是不能在前灣海域到處遊蕩的。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"어쭙잖은 각오라면 지금이라도 얌전히 돌아가라고.","JPN":"中途半端な覚悟なら、今からでも大人しく帰ることだ。","ENG":"If you're not fully committed to this, I suggest you get off this ship.","TWN":"如果你只是半吊子的心情，現在就乖乖回去吧。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"관심 없으니 닻이나 올려요, 터커.","JPN":"その気はないですから、錨を上げてください、ターカーさん。","ENG":"I don't care. So raise the anchor, Tucker.","TWN":"我不在乎那個。所以趕緊起錨吧，塔克先生。"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"그 잘난 법률이 밥 먹여주지는 않잖아요.","JPN":"その大そうな法律がご飯を食べさせてくれるわけじゃないですから。","ENG":"Laws don't put food on the table, right?","TWN":"那些自以為是的法律又不能當飯吃……"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"생각보다 한적하네요.","JPN":"思ったより静かですね。","ENG":"It's more peaceful out here than I thought.","TWN":"比我想像的還要安靜呢。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"뭘 모르는구만. 원래 바다는 잠잠할 때가 가장 무서운 법이야.","JPN":"わかってないな。海は静かな時が一番怖いんだ。","ENG":"Rookie mistake. The sea is the scariest when it's quiet like this.","TWN":"哼哼，你什麼都不懂。這種平靜的海洋才是最可怕的。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"긴장을 풀면 순식간에 바다 위의 미아가 되어버릴걸?","JPN":"油断すると、一瞬で迷子になるぞ。","ENG":"The second you let your guard down, you'll instantly become stranded at sea.","TWN":"一放鬆警惕，就會瞬間變成海上的迷途之人喔？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"봐. 말하기가 무섭게 소란이잖아.","JPN":"ほら。噂をしたから騒がしくなった。","ENG":"Well, speak of the devil.","TWN":"你看，才剛說完事情就來了。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"자식들아, 일할 시간이다!","JPN":"おらぁ、仕事の時間だ！","ENG":"Me hearties! It's time to go to work!","TWN":"大家，該做事了！"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"다들 무기 챙겨서 갑판 위로…","JPN":"全員、武器を持ってデッキの上に……","ENG":"Grab your weapons and get to the deck–","TWN":"大家都準備好武器，上甲板……"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":" 응?","JPN":" うん？","ENG":" Hmm?","TWN":"嗯？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"푸하-!","JPN":"ぷはーっ！","ENG":"*Gasp*","TWN":"噗哈——!"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};